import{_ as e,o as s,c as n,ag as t}from"./chunks/framework.BqKFDx7z.js";const h=JSON.parse('{"title":"Introduction","description":"Learn what TalaDB is, how it works, and why it was built — a local-first document database powered by a Rust core that runs in the browser, Node.js, and React Native.","frontmatter":{"title":"Introduction","description":"Learn what TalaDB is, how it works, and why it was built — a local-first document database powered by a Rust core that runs in the browser, Node.js, and React Native."},"headers":[],"relativePath":"introduction.md","filePath":"introduction.md"}'),r={name:"introduction.md"};function p(i,a,o,l,c,d){return s(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><h2 id="what-is-taladb" tabindex="-1">What is TalaDB? <a class="header-anchor" href="#what-is-taladb" aria-label="Permalink to &quot;What is TalaDB?&quot;">​</a></h2><p>TalaDB is an open-source, <strong>local-first document database</strong> built in Rust and designed for the modern JavaScript ecosystem. It lets React and React Native developers store and query structured data directly on the user&#39;s device — with no server, no network dependency, and no cloud subscription.</p><p>Data is stored as schemaless JSON-like documents, organised into named <strong>collections</strong>. Queries use a MongoDB-inspired filter DSL so the API feels familiar without requiring a separate query language.</p><p>The same Rust core powers every runtime:</p><table tabindex="0"><thead><tr><th>Runtime</th><th>Package</th><th>Mechanism</th></tr></thead><tbody><tr><td>Browser</td><td><code>taladb-wasm</code></td><td><code>wasm-bindgen</code> + OPFS</td></tr><tr><td>Node.js</td><td><code>taladb-node</code></td><td><code>napi-rs</code> native module</td></tr><tr><td>React Native</td><td><code>taladb-react-native</code></td><td>JSI HostObject (C FFI)</td></tr></tbody></table><p>All three surfaces expose a single unified TypeScript API from the <code>taladb</code> package, so application code never needs to branch on platform.</p><h2 id="architecture-overview" tabindex="-1">Architecture overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture overview&quot;">​</a></h2><p>TalaDB is built in three layers:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Layer 3 — TypeScript / JavaScript API                        │</span></span>
<span class="line"><span>│  wasm-bindgen (browser) · napi-rs (Node.js) · JSI (RN)       │</span></span>
<span class="line"><span>└──────────────────────────────┬───────────────────────────────┘</span></span>
<span class="line"><span>                               │  postcard bytes</span></span>
<span class="line"><span>┌──────────────────────────────▼───────────────────────────────┐</span></span>
<span class="line"><span>│  Layer 2 — Document Engine  (taladb-core)                     │</span></span>
<span class="line"><span>│  Document model · Secondary indexes · Query planner/executor  │</span></span>
<span class="line"><span>└──────────────────────────────┬───────────────────────────────┘</span></span>
<span class="line"><span>                               │  raw key/value bytes</span></span>
<span class="line"><span>┌──────────────────────────────▼───────────────────────────────┐</span></span>
<span class="line"><span>│  Layer 1 — KV Storage Engine                                  │</span></span>
<span class="line"><span>│  redb (native / Node.js) · OPFS backend (browser)            │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>Layer 1 — Storage.</strong> <a href="https://github.com/cberner/redb" target="_blank" rel="noreferrer">redb</a> is a pure-Rust, B-tree embedded key-value store. In the browser, TalaDB replaces it with a custom OPFS backend that uses <code>FileSystemSyncAccessHandle</code> inside a SharedWorker, giving durable on-device persistence without IndexedDB&#39;s overhead.</p><p><strong>Layer 2 — Document engine.</strong> <code>taladb-core</code> sits above the storage layer and knows nothing about JavaScript bindings. It provides the document model, secondary index key encoding, the filter/update AST, the query planner, and schema migrations.</p><p><strong>Layer 3 — Bindings.</strong> Thin platform-specific wrappers translate JavaScript values into the Rust types that <code>taladb-core</code> expects and route them through the storage layer.</p><h2 id="repository-structure" tabindex="-1">Repository structure <a class="header-anchor" href="#repository-structure" aria-label="Permalink to &quot;Repository structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>taladb/</span></span>
<span class="line"><span>├── Cargo.toml                      # Rust workspace</span></span>
<span class="line"><span>├── pnpm-workspace.yaml</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── packages/</span></span>
<span class="line"><span>│   ├── taladb-core/                # Pure Rust core — no JS bindings</span></span>
<span class="line"><span>│   │   └── src/</span></span>
<span class="line"><span>│   │       ├── document.rs         # Value enum, Document struct (ULID IDs)</span></span>
<span class="line"><span>│   │       ├── engine.rs           # StorageBackend trait + redb implementation</span></span>
<span class="line"><span>│   │       ├── index.rs            # Secondary index key encoding</span></span>
<span class="line"><span>│   │       ├── collection.rs       # CRUD operations</span></span>
<span class="line"><span>│   │       ├── migration.rs        # Schema versioning</span></span>
<span class="line"><span>│   │       ├── crypto.rs           # AES-GCM-256 encryption wrapper</span></span>
<span class="line"><span>│   │       ├── watch.rs            # Live query subscriptions</span></span>
<span class="line"><span>│   │       └── query/</span></span>
<span class="line"><span>│   │           ├── filter.rs       # Filter AST</span></span>
<span class="line"><span>│   │           ├── planner.rs      # Index selection</span></span>
<span class="line"><span>│   │           └── executor.rs     # Scan + post-filter</span></span>
<span class="line"><span>│   │</span></span>
<span class="line"><span>│   ├── taladb-wasm/                # Browser (wasm-bindgen + OPFS)</span></span>
<span class="line"><span>│   ├── taladb-node/                # Node.js (napi-rs native module)</span></span>
<span class="line"><span>│   ├── taladb-react-native/        # React Native (JSI HostObject + C FFI)</span></span>
<span class="line"><span>│   └── taladb/                     # Unified TypeScript package</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>└── examples/</span></span>
<span class="line"><span>    ├── web-vite/                   # React + Vite demo</span></span>
<span class="line"><span>    ├── expo-app/                   # Expo React Native demo</span></span>
<span class="line"><span>    └── node-script/                # Node.js script demo</span></span></code></pre></div><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>TalaDB is under <strong>active development</strong>. The Rust core, browser WASM, and Node.js bindings are functional and tested. The React Native JSI layer has a complete scaffold but full iOS / Android integration requires platform-specific build tooling. APIs may change before a stable 1.0 release.</p><p>Follow the <a href="https://github.com/thinkgrid-labs/taladb" target="_blank" rel="noreferrer">GitHub repository</a> for progress updates.</p>`,18)])])}const b=e(r,[["render",p]]);export{h as __pageData,b as default};
